    def is_geojson_instance(data):
        return isinstance(data, (list, dict)) or (isinstance(data, str) and is_geojson_file_path(data))

    def is_sql_query_instance(data, credentials):
        return isinstance(data, str) and is_sql_query(data)

    def is_table_instance(data, credentials):
        return isinstance(data, str) and not is_sql_query(data)

    def _init_strategy(self, data, credentials=None, schema=None):
        credentials = credentials or _get_default_credentials()

        if isinstance(data, pd.DataFrame):
            return self._getDataFrameDataset(data)
        elif self.is_geojson_instance(data):
            return self._getDataFrameDataset(load_geojson(data))
        elif self.is_sql_query_instance(data, credentials):
            return self._getQueryDataset(data, credentials)
        elif self.is_table_instance(data, credentials):
            return self._getTableDataset(data, credentials, schema)
        else:
            raise ValueError('We can not detect the Dataset type')
```

